+/**
+ * Runs an agent until it finishes. A delegate_task starts another run and its
+ * result is supplied as a tool_result when the delegating agent is invoked
+ * again. Keeping this here (rather than in a provider) lets every registered
+ * provider participate in the same delegation protocol.
+ */
+async function* runAgentConversation(
+  agentId: string,
+  instructions: string,
+  request: ChatRequest,
+  abortController: AbortController,
+  debugMode: boolean,
+  delegationPath: string[],
+  invocation: { nextToolUseId: () => string },
+  isSubAgent = false
+): AsyncGenerator<StreamResponse, AgentRunResult> {
+  const provider = globalRegistry.getProviderForAgent(agentId);
+  const agentConfig = globalRegistry.getAgent(agentId);
+
+  if (!provider || !agentConfig) {
+    const error = `Agent '${agentId}' not found or provider not available`;
+    // An unknown delegated agent is both visible to the client and returned to
+    // its caller. Provider failures, in contrast, are only returned as a tool result.
+    if (isSubAgent) {
+      yield { type: "error", error };
+    }
+    return { content: "", error };
+  }
+
+  let content = "";
+  const context: ProviderChatRequest["context"] = [];
+
+  while (true) {
+    let delegated = false;
+    let providerError: string | undefined;
+    const providerRequest: ProviderChatRequest = {
+      message: instructions,
+      sessionId: request.sessionId,
+      requestId: request.requestId,
+      workingDirectory: request.workingDirectory || agentConfig.workingDirectory,
+      context: context.length > 0 ? context : undefined,
+    };
+
+    for await (const response of provider.executeChat(providerRequest, {
+      debugMode,
+      abortController,
+      temperature: agentConfig.config?.temperature,
+      maxTokens: agentConfig.config?.maxTokens,
+    })) {
+      if (response.type === "text") {
+        const text = response.content || "";
+        content += text;
+        yield {
+          type: "claude_json",
+          data: { type: "assistant", content: text, model: response.metadata?.model },
+        };
+      } else if (response.type === "tool_use" && response.toolName === "delegate_task") {
+        delegated = true;
+        const input = (response.toolInput || {}) as DelegationToolInput;
+        const toolUseId = response.toolUseId || invocation.nextToolUseId();
+        yield delegationToolUse(toolUseId, input, request.sessionId);
+
+        const delegatedAgentId = typeof input.agent_id === "string" ? input.agent_id : "";
+        const delegatedInstructions = typeof input.instructions === "string" ? input.instructions : "";
+        let childResult: AgentRunResult;
+
+        if (!delegatedAgentId) {
+          childResult = { content: "", error: "delegate_task requires an agent_id" };
+        } else if (delegationPath.includes(delegatedAgentId)) {
+          const error = `Circular delegation detected for agent '${delegatedAgentId}'`;
+          yield { type: "error", error };
+          childResult = { content: "", error };
+        } else {
+          childResult = yield* runAgentConversation(
+            delegatedAgentId,
+            delegatedInstructions,
+            request,
+            abortController,
+            debugMode,
+            [...delegationPath, delegatedAgentId],
+            invocation,
+            true
+          );
+        }
+
+        const toolResult = delegationToolResult(toolUseId, childResult);
+        // The JSON string is the exact feedback supplied to the next invocation.
+        context.push(
+          { role: "assistant", content: JSON.stringify({ type: "tool_use", id: toolUseId, name: "delegate_task", input }) },
+          { role: "user", content: JSON.stringify(toolResult) }
+        );
+        yield delegationResultMessage(toolResult, request.sessionId);
+      } else if (response.type === "error") {
+        providerError = response.error || "Agent execution failed";
+        break;
+      }
+    }
+
+    if (providerError) {
+      if (!isSubAgent) {
+        yield { type: "error", error: providerError };
+      }
+      return { content, error: providerError };
+    }
+
+    if (!delegated) {
+      return { content };
+    }
+  }
+}
